using System;using System.IO;namespace EditorBrowser{    internal enum BrowserKind    {        None,        Chrome,        Edge,    }    internal sealed class BrowserInfo    {        public BrowserKind Kind { get; }        public string ExecutablePath { get; }        public BrowserInfo(BrowserKind kind, string path)        {            Kind = kind;            ExecutablePath = path;        }        public bool IsAvailable => Kind != BrowserKind.None && !string.IsNullOrEmpty(ExecutablePath);    }    /// <summary>    /// Chrome/Edge ?ㅼ튂 媛먯?. ?덉??ㅽ듃由??섏〈???쇳븯怨??뚮젮吏??ㅼ튂 寃쎈줈留??먭??쒕떎.    /// (.NET Standard 2.1 ?섍꼍?먯꽌 Microsoft.Win32.Registry??蹂꾨룄 NuGet ?⑦궎吏媛 ?꾩슂?섎?濡?    ///  ?뚯씪 ?쒖뒪??湲곕컲 媛먯?濡??듭씪 ???대???Chrome ?깆? V2?먯꽌 EditorPref ?ㅻ쾭?쇱씠??吏???덉젙.)    /// </summary>    internal static class BrowserDetector    {        public static BrowserInfo Detect()        {            var chrome = FindFirstExisting(ChromeCandidatePaths());            if (!string.IsNullOrEmpty(chrome))                return new BrowserInfo(BrowserKind.Chrome, chrome);            var edge = FindFirstExisting(EdgeCandidatePaths());            if (!string.IsNullOrEmpty(edge))                return new BrowserInfo(BrowserKind.Edge, edge);            return new BrowserInfo(BrowserKind.None, null);        }        private static string[] ChromeCandidatePaths()        {            var pf  = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles);            var pf86 = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFilesX86);            var local = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);            return new[]            {                Path.Combine(pf,  "Google", "Chrome", "Application", "chrome.exe"),                Path.Combine(pf86, "Google", "Chrome", "Application", "chrome.exe"),                Path.Combine(local, "Google", "Chrome", "Application", "chrome.exe"),            };        }        private static string[] EdgeCandidatePaths()        {            var pf  = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFiles);            var pf86 = Environment.GetFolderPath(Environment.SpecialFolder.ProgramFilesX86);            return new[]            {                Path.Combine(pf86, "Microsoft", "Edge", "Application", "msedge.exe"),                Path.Combine(pf,  "Microsoft", "Edge", "Application", "msedge.exe"),            };        }        private static string FindFirstExisting(string[] paths)        {            foreach (var p in paths)            {                try                {                    if (!string.IsNullOrEmpty(p) && File.Exists(p))                        return p;                }                catch                {                    // 沅뚰븳쨌UNC ???덉쇅??臾댁떆?섍퀬 ?ㅼ쓬 ?꾨낫濡?                }            }            return null;        }    }}